action.old_str:
// 判断 StartOfLine 和 LeadingSpace
bool startOfLine = (column == 1);
bool leadingSpace = false;

if (!startOfLine && line == prevTokenLine) {
  // 在同一行，检查是否紧接前一个token
  // 如果当前token的起始列号 > 前一个token的结束列号 + 1，则中间有空格
  if (column > prevTokenEndCol + 1) {
    leadingSpace = true;
  }
} else if (column > 1) {
  // 新行但不在行首，前面可能有空格（比如缩进）
  leadingSpace = true;
}

action.new_str:
// 判断 StartOfLine 和 LeadingSpace
bool startOfLine = (line != prevTokenLine); // 新行的第一个token
bool leadingSpace = false;

if (line == prevTokenLine) {
  // 在同一行，检查是否紧接前一个token
  // 如果当前token的起始列号 > 前一个token的结束列号 + 1，则中间有空格
  if (column > prevTokenEndCol + 1) {
    leadingSpace = true;
  }
} else if (column > 1) {
  // 新行但不在列1（有缩进），前面有空格
  leadingSpace = true;
}

